import{_ as e,o as r,c as i,ah as h}from"./chunks/framework.NjRSjnv-.js";const C=JSON.parse('{"title":"QUIC","description":"","frontmatter":{"title":"QUIC","order":6},"headers":[],"relativePath":"server/network/proto/quic.md","filePath":"server/network/proto/quic.md"}'),n={name:"server/network/proto/quic.md"};function l(t,a,c,o,p,T){return r(),i("div",null,[...a[0]||(a[0]=[h('<h1 id="quic-协议" tabindex="-1">QUIC 协议 <a class="header-anchor" href="#quic-协议" aria-label="Permalink to “QUIC 协议”">​</a></h1><p>QUIC（Quick UDP Internet Connections）是 Google 开发的基于 UDP 的传输协议，旨在解决 TCP 的问题。QUIC 提供可靠传输、流量控制、拥塞控制，支持多路复用、连接迁移、0-RTT 握手。</p><h2 id="为什么需要-quic" tabindex="-1">为什么需要 QUIC <a class="header-anchor" href="#为什么需要-quic" aria-label="Permalink to “为什么需要 QUIC”">​</a></h2><h3 id="tcp-的问题" tabindex="-1">TCP 的问题 <a class="header-anchor" href="#tcp-的问题" aria-label="Permalink to “TCP 的问题”">​</a></h3><p>队头阻塞：TCP 是字节流协议，一个报文段丢失，后续报文段无法处理，导致队头阻塞。</p><p>连接建立慢：TCP 三次握手需要 1-RTT，TLS 握手需要 2-RTT，共 3-RTT。TLS 1.2 优化后需要 2-RTT。</p><p>连接僵化：中间设备（如防火墙、NAT）记录 TCP 连接状态，IP 变化时连接中断。</p><p>协议僵化：TCP 协议在操作系统内核中，升级困难。中间设备依赖 TCP 的特性（如拥塞控制），修改 TCP 困难。</p><h3 id="quic-的解决方案" tabindex="-1">QUIC 的解决方案 <a class="header-anchor" href="#quic-的解决方案" aria-label="Permalink to “QUIC 的解决方案”">​</a></h3><p>多路复用：QUIC 支持多路复用，多个流独立传输，一个流的丢包不影响其他流，解决队头阻塞。</p><p>快速握手：QUIC 握手只需要 0-RTT 或 1-RTT，比 TCP + TLS 快。</p><p>连接迁移：QUIC 连接由 Connection ID 标识，IP 变化时 Connection ID 不变，连接不中断。</p><p>用户空间实现：QUIC 在用户空间实现，协议升级不需要操作系统升级。</p><h2 id="quic-数据包" tabindex="-1">QUIC 数据包 <a class="header-anchor" href="#quic-数据包" aria-label="Permalink to “QUIC 数据包”">​</a></h2><h3 id="数据包格式" tabindex="-1">数据包格式 <a class="header-anchor" href="#数据包格式" aria-label="Permalink to “数据包格式”">​</a></h3><p>Public Header：公共头，包含 Connection ID、包编号、版本号。</p><p>Private Header：私有头，包含密钥、流 ID、偏移量。</p><p>Payload：负载，包含流控制帧、握手数据、应用数据。</p><h3 id="connection-id" tabindex="-1">Connection ID <a class="header-anchor" href="#connection-id" aria-label="Permalink to “Connection ID”">​</a></h3><p>Connection ID 是 64 位随机数，标识 QUIC 连接。Connection ID 在连接期间不变，IP 变化时 Connection ID 不变，连接不中断。</p><p>Connection ID 可以加密，防止中间设备跟踪连接。</p><h3 id="包编号" tabindex="-1">包编号 <a class="header-anchor" href="#包编号" aria-label="Permalink to “包编号”">​</a></h3><p>包编号是 62 位整数，标识数据包的序号。包编号单向递增，0-RTT 包的包编号从 0 开始，1-RTT 包的包编号从 1 开始。</p><p>包编号用于 ACK、去重、拥塞控制。</p><h2 id="quic-流" tabindex="-1">QUIC 流 <a class="header-anchor" href="#quic-流" aria-label="Permalink to “QUIC 流”">​</a></h2><h3 id="流的概念" tabindex="-1">流的概念 <a class="header-anchor" href="#流的概念" aria-label="Permalink to “流的概念”">​</a></h3><p>流是 QUIC 的虚拟通道，多个流共享一个 QUIC 连接。流是单向的或双向的，每个流有独立的流 ID。</p><p>流 A 的丢包不影响流 B，解决队头阻塞。</p><h3 id="流-id" tabindex="-1">流 ID <a class="header-anchor" href="#流-id" aria-label="Permalink to “流 ID”">​</a></h3><p>流 ID 是 62 位整数，标识流。客户端发起的流 ID 是奇数，服务端发起的流 ID 是偶数。</p><p>流 ID 可以协商，减少流 ID 冲突。</p><h3 id="流控制" tabindex="-1">流控制 <a class="header-anchor" href="#流控制" aria-label="Permalink to “流控制”">​</a></h3><p>QUIC 支持流级和连接级的流控制。流级流控制控制单个流的数据量，连接级流控制控制整个连接的数据量。</p><p>流控制通过 MAX_DATA 帧实现，接收方告诉发送方可以接收多少字节。</p><h2 id="quic-握手" tabindex="-1">QUIC 握手 <a class="header-anchor" href="#quic-握手" aria-label="Permalink to “QUIC 握手”">​</a></h2><h3 id="_0-rtt-握手" tabindex="-1">0-RTT 握手 <a class="header-anchor" href="#_0-rtt-握手" aria-label="Permalink to “0-RTT 握手”">​</a></h3><p>客户端发送 0-RTT 包，包含应用数据，使用之前缓存的密钥加密。服务端收到后解密，处理应用数据。</p><p>0-RTT 握手减少 1 个 RTT，但存在重放攻击风险。服务端可以检测重放攻击，拒绝 0-RTT 包。</p><h3 id="_1-rtt-握手" tabindex="-1">1-RTT 握手 <a class="header-anchor" href="#_1-rtt-握手" aria-label="Permalink to “1-RTT 握手”">​</a></h3><p>客户端发送 Client Hello，包含随机数、支持的加密套件。</p><p>服务端回复 Server Hello、证书、密钥、Finished。双方计算会话密钥。</p><p>客户端验证证书，回复 Finished，完成握手。</p><p>1-RTT 握手类似于 TLS 1.3，比 TLS 1.2 快 1 个 RTT。</p><h2 id="quic-的可靠性" tabindex="-1">QUIC 的可靠性 <a class="header-anchor" href="#quic-的可靠性" aria-label="Permalink to “QUIC 的可靠性”">​</a></h2><h3 id="ack-确认" tabindex="-1">ACK 确认 <a class="header-anchor" href="#ack-确认" aria-label="Permalink to “ACK 确认”">​</a></h3><p>QUIC 使用 ACK 确认数据包的接收。ACK 包含接收到的最大包编号、ACK 延迟时间、ACK 块。</p><p>ACK 块：记录收到的包编号范围，减少 ACK 大小。</p><h3 id="超时重传" tabindex="-1">超时重传 <a class="header-anchor" href="#超时重传" aria-label="Permalink to “超时重传”">​</a></h3><p>发送方发送数据后启动定时器，如果超时未收到 ACK，则重传数据。超时时间根据 RTT 动态调整。</p><p>QUIC 支持探测定时器，避免虚假超时。</p><h3 id="前向纠错" tabindex="-1">前向纠错 <a class="header-anchor" href="#前向纠错" aria-label="Permalink to “前向纠错”">​</a></h3><p>前向纠错（FEC）发送冗余数据，接收方可以通过冗余数据恢复丢失的数据，减少重传。</p><h2 id="quic-的拥塞控制" tabindex="-1">QUIC 的拥塞控制 <a class="header-anchor" href="#quic-的拥塞控制" aria-label="Permalink to “QUIC 的拥塞控制”">​</a></h2><h3 id="拥塞控制算法" tabindex="-1">拥塞控制算法 <a class="header-anchor" href="#拥塞控制算法" aria-label="Permalink to “拥塞控制算法”">​</a></h3><p>QUIC 支持可插拔的拥塞控制算法，如 Cubic、BBR、Reno。默认使用 Cubic。</p><p>QUIC 的拥塞控制与 TCP 类似，有慢启动、拥塞避免、快速重传、快速恢复。</p><h3 id="rtt-测量" tabindex="-1">RTT 测量 <a class="header-anchor" href="#rtt-测量" aria-label="Permalink to “RTT 测量”">​</a></h3><p>QUIC 测量最小 RTT 和平滑 RTT（SRTT），用于计算超时时间和拥塞窗口。</p><h2 id="quic-的安全" tabindex="-1">QUIC 的安全 <a class="header-anchor" href="#quic-的安全" aria-label="Permalink to “QUIC 的安全”">​</a></h2><h3 id="加密" tabindex="-1">加密 <a class="header-anchor" href="#加密" aria-label="Permalink to “加密”">​</a></h3><p>QUIC 使用 TLS 1.3 加密，所有数据包（除 Initial 包）都加密。</p><p>QUIC 使用 ChaCha20-Poly1305 或 AES-GCM 加密算法。</p><h3 id="认证" tabindex="-1">认证 <a class="header-anchor" href="#认证" aria-label="Permalink to “认证”">​</a></h3><p>QUIC 使用 TLS 1.3 认证，服务端发送证书，客户端验证证书。</p><p>QUIC 支持 Client Certificate，双向认证。</p><h3 id="防重放攻击" tabindex="-1">防重放攻击 <a class="header-anchor" href="#防重放攻击" aria-label="Permalink to “防重放攻击”">​</a></h3><p>0-RTT 包存在重放攻击风险，攻击者可以重放 0-RTT 包。</p><p>解决方案：服务端记录 0-RTT 包的签名，检测重放。服务端可以拒绝 0-RTT 包，只接受 1-RTT 包。</p><h2 id="quic-的应用" tabindex="-1">QUIC 的应用 <a class="header-anchor" href="#quic-的应用" aria-label="Permalink to “QUIC 的应用”">​</a></h2><h3 id="http-3" tabindex="-1">HTTP/3 <a class="header-anchor" href="#http-3" aria-label="Permalink to “HTTP/3”">​</a></h3><p>HTTP/3 基于 QUIC，解决 HTTP/2 的 TCP 队头阻塞问题。HTTP/3 保留 HTTP/2 的二进制协议、头部压缩、多路复用。</p><h3 id="chrome" tabindex="-1">Chrome <a class="header-anchor" href="#chrome" aria-label="Permalink to “Chrome”">​</a></h3><p>Chrome 默认开启 QUIC，访问 Google 服务（如 YouTube、Gmail）使用 QUIC。</p><h3 id="gquic-vs-iquic" tabindex="-1">gQUIC vs iQUIC <a class="header-anchor" href="#gquic-vs-iquic" aria-label="Permalink to “gQUIC vs iQUIC”">​</a></h3><p>gQUIC：Google 的 QUIC 实现，加密、流控制与 HTTP/2 绑定。</p><p>iQUIC：IETF 标准化的 QUIC，传输层与 HTTP 分离，更通用。</p><h2 id="quic-vs-tcp" tabindex="-1">QUIC vs TCP <a class="header-anchor" href="#quic-vs-tcp" aria-label="Permalink to “QUIC vs TCP”">​</a></h2><h3 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to “优势”">​</a></h3><p>快速握手：QUIC 0-RTT 握手，TCP 需要 1-RTT + TLS 2-RTT。</p><p>多路复用：QUIC 流独立，TCP 字节流队头阻塞。</p><p>连接迁移：QUIC IP 变化连接不中断，TCP IP 变化连接中断。</p><p>用户空间：QUIC 在用户空间实现，升级方便。TCP 在内核中，升级困难。</p><h3 id="劣势" tabindex="-1">劣势 <a class="header-anchor" href="#劣势" aria-label="Permalink to “劣势”">​</a></h3><p>普及率：QUIC 普及率低于 TCP，部分网络设备丢弃 QUIC 包。</p><p>性能：QUIC 加密开销大，性能可能低于 TCP。</p><p>调试：QUIC 协议复杂，调试困难。</p><p>QUIC 是下一代传输协议，解决 TCP 的问题，适合低延迟、高吞吐场景。理解 QUIC 的原理和权衡，有助于选择合适的传输协议。</p>',87)])])}const s=e(n,[["render",l]]);export{C as __pageData,s as default};
